import base64, os
DEST = r"D:\Doc\Biz\Projet Behanian\Claude\Behanian_Project\templates\restaurant\index.html"
DATA = ""
content = base64.b64decode(DATA).decode("utf-8")
print("Taille:", len(content), "bytes")
print("Lignes:", content.count("\n"))
print("switchView:", "function switchView" in content)
print("ajouterBoisson:", "function ajouterBoisson" in content)
if os.path.exists(DEST):
    with open(DEST, "rb") as f: old = f.read()
    with open(DEST + ".bak_deploy", "wb") as f: f.write(old)
    print("Backup cree:", len(old), "bytes")
with open(DEST, "w", encoding="utf-8") as f:
    f.write(content)
with open(DEST, "r", encoding="utf-8") as f: v = f.read()
ok = "function switchView" in v and "function ajouterBoisson" in v
print("SUCCES - Redemarrez le serveur" if ok else "ERREUR")